+    if (st == ASX_E_PENDING && asx_deadline_is_expired(&state->deadline)) {
+        uint32_t i;
+        state->timed_out = 1;
+        for (i = 0; i < state->race.count; i++) {
+            branch_cancel_after_final_poll(&state->race.branches[i], self);
+        }
