+
+/* Law: join(ok, ok) = ok */
+TEST(law_join_all_ok) {
+    asx_join_state state;
+    MUST_OK(asx_join_init(&state));
+    MUST_OK(asx_join_add(&state, poll_ok, NULL));
+    MUST_OK(asx_join_add(&state, poll_ok, NULL));
+    ASSERT_EQ(asx_join_poll(&state, 1), ASX_OK);
