+static int g_iter_count;
+static asx_symbol_id g_iter_ids[16];
+
+static int iter_collect(asx_symbol_id id, void *ctx) {
+    (void)ctx;
+    if (g_iter_count < 16) g_iter_ids[g_iter_count] = id;
+    g_iter_count++;
